import{c as i,Z as s,Q as u,j as d,g as t,n as o,o as a,m as n,av as p}from"./chunks/framework.BPKcPtvA.js";const v=JSON.parse('{"title":"Sell autonomously via MCP","description":"With a Scoped session installed, ask your own LLM to sell a position — it submits autonomously and returns a tx hash, no deep-link.","frontmatter":{"title":"Sell autonomously via MCP","description":"With a Scoped session installed, ask your own LLM to sell a position — it submits autonomously and returns a tx hash, no deep-link."},"headers":[],"relativePath":"guide/mcp/sell.md","filePath":"guide/mcp/sell.md","lastUpdated":1780218602000}'),c={name:"guide/mcp/sell.md"};function h(m,e,g,y,b,f){const l=s("TaskMeta"),r=s("ExpectedResult");return u(),d("div",null,[e[1]||(e[1]=t("h1",{id:"sell-autonomously-via-mcp",tabindex:"-1"},[o("Sell autonomously via MCP "),t("a",{class:"header-anchor",href:"#sell-autonomously-via-mcp","aria-label":'Permalink to "Sell autonomously via MCP"'},"​")],-1)),a(l,{time:"~3 min",role:"Investor",needs:"A Scoped session installed (M1+M2), an open position"}),e[2]||(e[2]=n('<blockquote><p><strong>What you&#39;ll do:</strong> ask your own LLM to sell part of a holding in plain language — the broker submits it autonomously with your Scoped key and you verify the settlement, <strong>no dashboard deep-link</strong>.</p></blockquote><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><p>A <strong>Scoped session</strong> installed in the broker (<a href="/guide/mcp/arm-scoped">M1</a> + <a href="/guide/mcp/install">M2</a>) and an open position to sell (<a href="/guide/investor/buy">I5 · Buy</a>). For an end-to-end autonomous round-trip, do <a href="/guide/mcp/buy">M4 · Buy autonomously</a> first.</p></div><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>In your host, type <strong>&quot;Sell 2 shares of CETES.&quot;</strong></li><li>Your LLM calls the MuHaven sell tool; the broker <strong>signs and submits autonomously</strong> and returns a <strong>tx hash</strong> — no deep-link, no passkey prompt.</li><li>A sell within the token&#39;s per-epoch instant cap settles <strong>instantly</strong>; a larger sell is <strong>queued</strong> and settles in a later epoch — claim it later (<a href="/guide/investor/redemption-queue">I9 · Redemption-queue claim</a>).</li><li>Verify: ask <strong>&quot;Show my recent activity&quot;</strong>, or open <a href="/guide/investor/activity">Activity</a>.</li></ol><div class="warning custom-block"><p class="custom-block-title">Over-sell is clamped</p><p>If you ask to sell more than you hold, the contract clamps to your actual balance — you sell your full position, not a phantom amount. See <a href="/guide/investor/sell">I7 · Sell</a>.</p></div><div class="tip custom-block"><p class="custom-block-title">Two carve-outs to remember</p><ul><li><strong>Portfolio rebalance</strong> isn&#39;t an autonomous MCP tool — ask <strong>HavenBot</strong> to rebalance to targets, or use the <strong>Auto-rebalance</strong> panel on <code>/portfolio</code> (<a href="/guide/agent/autonomous">H4 · Buy &amp; sell autonomously</a>).</li><li><strong>Converting USDC ↔ mhUSDC</strong> (deposit/withdraw) always uses a passkey <strong>dashboard deep-link</strong> — never autonomous submission.</li></ul></div><h2 id="expected-result" tabindex="-1">Expected result <a class="header-anchor" href="#expected-result" aria-label="Permalink to &quot;Expected result&quot;">​</a></h2>',8)),a(r,null,{default:p(()=>[...e[0]||(e[0]=[o(" The sell either settles ",-1),t("strong",null,"instantly",-1),o(" or lands in the ",-1),t("strong",null,"redemption queue",-1),o(", and your LLM returns a ",-1),t("strong",null,"tx hash",-1),o(" — ",-1),t("strong",null,"no deep-link",-1),o(". It shows up when you ask ",-1),t("em",null,'"show my recent activity"',-1),o(". ",-1)])]),_:1}),e[3]||(e[3]=n('<h2 id="if-something-goes-wrong" tabindex="-1">If something goes wrong <a class="header-anchor" href="#if-something-goes-wrong" aria-label="Permalink to &quot;If something goes wrong&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Fix</th></tr></thead><tbody><tr><td>Sell returns a dashboard deep-link instead of running</td><td>No live Scoped session installed — mint one (<a href="/guide/mcp/arm-scoped">M1</a>) and confirm <code>muhaven-broker doctor</code>&#39;s signer matches.</td></tr><tr><td>Sale was queued, not instant</td><td>The amount exceeded the per-epoch instant cap — settle the queued portion later (<a href="/guide/investor/redemption-queue">I9</a>).</td></tr><tr><td>You asked to sell more than you hold</td><td>The sell clamps to your full balance — not an error. See <a href="/guide/investor/sell">I7</a>.</td></tr></tbody></table><p>→ Next: <a href="/guide/reference">Reference appendix</a></p>',3))])}const S=i(c,[["render",h]]);export{v as __pageData,S as default};
